import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"Creating A Wireless OBDII Scanner","description":"Notes on Creating A Wireless OBDII Scanner.","frontmatter":{"title":"Creating A Wireless OBDII Scanner","description":"Notes on Creating A Wireless OBDII Scanner."},"headers":[],"relativePath":"obd2/guides/creating-a-wireless-obdii-scanner.md","filePath":"obd2/guides/creating-a-wireless-obdii-scanner.md"}'),l={name:"obd2/guides/creating-a-wireless-obdii-scanner.md"};function o(d,e,s,n,c,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="creating-a-wireless-obdii-scanner" tabindex="-1">Creating A Wireless OBDII Scanner <a class="header-anchor" href="#creating-a-wireless-obdii-scanner" aria-label="Permalink to &quot;Creating A Wireless OBDII Scanner&quot;">​</a></h1><p>Project documentation for building a <strong>wireless OBD-II scanner</strong> — bridging vehicle CAN/OBD to a phone or PC over Bluetooth/WiFi.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="../../../.gitbook/assets/JOHNKEENANIIIMQP2009.pdf">JOHNKEENANIIIMQP2009.pdf</a> — project report (local asset)</li></ul><h2 id="typical-build" tabindex="-1">Typical build <a class="header-anchor" href="#typical-build" aria-label="Permalink to &quot;Typical build&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Hardware / software</th></tr></thead><tbody><tr><td>Vehicle</td><td>OBD-II port (ISO 15765-4 CAN or legacy K-line)</td></tr><tr><td>Adapter</td><td>ELM327 or STN1110 chipset on UART</td></tr><tr><td>MCU</td><td>Arduino/ESP8266/ESP32 for AT command bridge</td></tr><tr><td>Wireless</td><td>Bluetooth SPP or WiFi TCP server</td></tr><tr><td>Client</td><td>Serial terminal, custom app, or python-OBD</td></tr></tbody></table><h2 id="flow" tabindex="-1">Flow <a class="header-anchor" href="#flow" aria-label="Permalink to &quot;Flow&quot;">​</a></h2><ol><li>MCU powers from OBD pin 16 (+12V regulated)</li><li>ELM327 handles <code>AT</code> init and OBD mode <code>01</code> PID requests</li><li>MCU forwards serial ↔ wireless link</li><li>Client sends <code>010C</code> (RPM), <code>010D</code> (speed), etc.</li></ol><h2 id="safety-legal" tabindex="-1">Safety &amp; legal <a class="header-anchor" href="#safety-legal" aria-label="Permalink to &quot;Safety &amp; legal&quot;">​</a></h2><ul><li>OBD queries while driving can distract — bench-test first</li><li>Do not transmit forged frames on public roads without authorization</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./README.html">OBD2 Guides</a></li><li><a href="./../elm327-datasheet.html">ELM327 Datasheet</a></li><li><a href="./../related-projects/README.html">Related Projects</a></li></ul>',12)])])}const p=a(l,[["render",o]]);export{b as __pageData,p as default};
